/**
 * Drag Validation Utilities
 *
 * Helpers for validating PM drag-and-drop operations including:
 * - Real-time constraint validation API calls
 * - Debounced validation for performance
 * - Impact assessment calculation
 *
 * @see specs/006-user-interface.md Section 6.3.4
 */

import type { DragValidationState, DragConstraintViolation, PmMoveImpact } from '../layers/types';

// =============================================================================
// Types
// =============================================================================

export interface ValidatePmMoveParams {
  pmId: string;
  currentDate: string;
  targetDate: string;
  trainId: string;
}

export interface ValidatePmMoveResponse {
  isValid: boolean;
  violations: DragConstraintViolation[];
  impact?: PmMoveImpact;
}

// =============================================================================
// Validation API
// =============================================================================

/**
 * Validates a PM move against all constraints.
 * Returns validation state including violations and impact assessment.
 */
export async function validatePmMove(
  params: ValidatePmMoveParams,
  options: { baseUrl?: string; signal?: AbortSignal } = {}
): Promise<DragValidationState> {
  const { baseUrl = '/api/v1', signal } = options;

  try {
    const response = await fetch(`${baseUrl}/pm/schedule/${params.pmId}/validate-move`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        targetDate: params.targetDate,
        trainId: params.trainId,
      }),
      signal,
    });

    if (!response.ok) {
      // Handle specific error codes
      if (response.status === 409) {
        // Conflict - PM is locked in Maximo
        return {
          isValid: false,
          message: 'PM is locked in Maximo (in progress)',
          violations: [{
            type: 'MAXIMO_LOCK',
            severity: 'ERROR',
            message: 'Cannot reschedule: PM is currently in progress in Maximo',
          }],
        };
      }

      throw new Error(`Validation failed: ${response.statusText}`);
    }

    const data = await response.json() as { data: ValidatePmMoveResponse };
    const result = data.data;

    return {
      isValid: result.isValid,
      message: result.violations.length > 0
        ? result.violations.map(v => v.message).join('; ')
        : null,
      violations: result.violations,
    };
  } catch (error) {
    // If request was aborted, return neutral state
    if (error instanceof Error && error.name === 'AbortError') {
      return {
        isValid: true,
        message: null,
        violations: [],
      };
    }

    // For network errors, return a warning (not blocking)
    return {
      isValid: true,
      message: 'Unable to validate constraints (network error)',
      violations: [{
        type: 'SERVICE_DEMAND',
        severity: 'WARNING',
        message: 'Constraint validation unavailable - proceed with caution',
      }],
    };
  }
}

/**
 * Client-side quick validation for immediate feedback.
 * Checks basic constraints without API call.
 */
export function quickValidatePmMove(
  params: ValidatePmMoveParams & {
    constraintStart: string;
    constraintEnd: string;
    isLocked: boolean;
  }
): DragValidationState {
  const violations: DragConstraintViolation[] = [];

  // Check if PM is locked
  if (params.isLocked) {
    violations.push({
      type: 'MAXIMO_LOCK',
      severity: 'ERROR',
      message: 'Cannot move: PM is locked',
    });
  }

  // Check compliance window
  const targetDate = new Date(params.targetDate);
  const windowStart = new Date(params.constraintStart);
  const windowEnd = new Date(params.constraintEnd);

  if (targetDate < windowStart) {
    violations.push({
      type: 'COMPLIANCE_WINDOW',
      severity: 'ERROR',
      message: `Target date ${params.targetDate} is before compliance window start (${params.constraintStart})`,
    });
  }

  if (targetDate > windowEnd) {
    violations.push({
      type: 'COMPLIANCE_WINDOW',
      severity: 'ERROR',
      message: `Target date ${params.targetDate} is after compliance window end (${params.constraintEnd})`,
    });
  }

  // Check if same date (no change)
  if (params.currentDate === params.targetDate) {
    return {
      isValid: true,
      message: null,
      violations: [],
    };
  }

  const hasErrors = violations.some(v => v.severity === 'ERROR');

  return {
    isValid: !hasErrors,
    message: violations.length > 0
      ? violations.map(v => v.message).join('; ')
      : null,
    violations,
  };
}

// =============================================================================
// Debounced Validation
// =============================================================================

interface DebouncedValidation {
  validate: (params: ValidatePmMoveParams) => void;
  cancel: () => void;
}

/**
 * Creates a debounced validation function for real-time drag feedback.
 * Cancels previous pending validation when a new position is provided.
 */
export function createDebouncedValidation(
  onResult: (result: DragValidationState) => void,
  options: { delay?: number; baseUrl?: string } = {}
): DebouncedValidation {
  const { delay = 150, baseUrl = '/api/v1' } = options;

  let timeoutId: NodeJS.Timeout | null = null;
  let abortController: AbortController | null = null;

  const validate = (params: ValidatePmMoveParams) => {
    // Cancel previous
    if (timeoutId) {
      clearTimeout(timeoutId);
    }
    if (abortController) {
      abortController.abort();
    }

    // Create new abort controller
    abortController = new AbortController();
    const signal = abortController.signal;

    // Schedule new validation
    timeoutId = setTimeout(async () => {
      const result = await validatePmMove(params, { baseUrl, signal });
      if (!signal.aborted) {
        onResult(result);
      }
    }, delay);
  };

  const cancel = () => {
    if (timeoutId) {
      clearTimeout(timeoutId);
      timeoutId = null;
    }
    if (abortController) {
      abortController.abort();
      abortController = null;
    }
  };

  return { validate, cancel };
}

// =============================================================================
// Impact Assessment
// =============================================================================

/**
 * Fetches detailed impact assessment for a PM move.
 * Used for the confirmation dialog.
 */
export async function getPmMoveImpact(
  params: ValidatePmMoveParams,
  options: { baseUrl?: string } = {}
): Promise<PmMoveImpact | null> {
  const { baseUrl = '/api/v1' } = options;

  try {
    const response = await fetch(`${baseUrl}/pm/schedule/${params.pmId}/move-impact`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        targetDate: params.targetDate,
        currentDate: params.currentDate,
      }),
    });

    if (!response.ok) {
      return null;
    }

    const data = await response.json() as { data: PmMoveImpact };
    return data.data;
  } catch {
    return null;
  }
}

/**
 * Commits a PM move to the server.
 * Returns true on success, throws on failure.
 */
export async function commitPmMove(
  params: ValidatePmMoveParams & { reason?: string },
  options: { baseUrl?: string } = {}
): Promise<{ success: boolean; explanation?: string }> {
  const { baseUrl = '/api/v1' } = options;

  const response = await fetch(`${baseUrl}/pm/schedule/${params.pmId}`, {
    method: 'PATCH',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      targetDate: params.targetDate,
      reason: params.reason || 'Manual reschedule via canvas drag-and-drop',
    }),
  });

  if (!response.ok) {
    const error = await response.json() as { error?: { message?: string } };
    throw new Error(error.error?.message || 'Failed to reschedule PM');
  }

  const data = await response.json() as {
    data: { explanation?: { changeType: string; impactAssessment: string } };
  };

  return {
    success: true,
    explanation: data.data.explanation?.impactAssessment,
  };
}

/**
 * Drag Confirmation Dialog
 *
 * Modal dialog for confirming PM reschedule operations.
 * Shows impact assessment and allows user to confirm or cancel.
 *
 * @see specs/006-user-interface.md Section 6.3.4
 */

import {
  Dialog,
  DialogBody,
  DialogFooter,
  Button,
  Intent,
  Callout,
  Spinner,
  Tag,
  Icon,
} from '@blueprintjs/core';

import type { PmMoveImpact, DragConstraintViolation } from './layers/types';

// =============================================================================
// Types
// =============================================================================

export interface DragConfirmationDialogProps {
  isOpen: boolean;
  pmCode: string;
  trainNumber: string;
  sourceDate: string;
  targetDate: string;
  impact: PmMoveImpact | null;
  violations: DragConstraintViolation[];
  isLoading: boolean;
  onConfirm: () => void;
  onCancel: () => void;
}

// =============================================================================
// Component
// =============================================================================

export function DragConfirmationDialog({
  isOpen,
  pmCode,
  trainNumber,
  sourceDate,
  targetDate,
  impact,
  violations,
  isLoading,
  onConfirm,
  onCancel,
}: DragConfirmationDialogProps) {
  const hasErrors = violations.some(v => v.severity === 'ERROR');
  const hasWarnings = violations.some(v => v.severity === 'WARNING');

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-US', {
      weekday: 'short',
      month: 'short',
      day: 'numeric',
      year: 'numeric',
    });
  };

  const daysDiff = Math.round(
    (new Date(targetDate).getTime() - new Date(sourceDate).getTime()) / (1000 * 60 * 60 * 24)
  );

  return (
    <Dialog
      isOpen={isOpen}
      onClose={onCancel}
      title="Confirm PM Reschedule"
      icon="calendar"
      canEscapeKeyClose={!isLoading}
      canOutsideClickClose={!isLoading}
      data-testid="drag-confirmation-dialog"
    >
      <DialogBody>
        {/* PM Info Header */}
        <div style={{
          display: 'flex',
          alignItems: 'center',
          gap: '12px',
          marginBottom: '16px',
          padding: '12px',
          backgroundColor: 'var(--pt-app-secondary-background-color, #f5f8fa)',
          borderRadius: '6px',
        }}>
          <Icon icon="wrench" size={24} color="var(--pt-icon-color)" />
          <div>
            <div style={{ fontWeight: 600, fontSize: '16px' }}>
              {pmCode}
            </div>
            <div style={{ color: 'var(--pt-text-muted)', fontSize: '13px' }}>
              Train {trainNumber}
            </div>
          </div>
        </div>

        {/* Date Change Summary */}
        <div style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          gap: '16px',
          marginBottom: '20px',
          padding: '16px',
          backgroundColor: 'var(--pt-app-background-color)',
          border: '1px solid var(--pt-divider-black)',
          borderRadius: '6px',
        }}>
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '11px', color: 'var(--pt-text-muted)', marginBottom: '4px' }}>
              FROM
            </div>
            <div style={{ fontWeight: 600 }}>
              {formatDate(sourceDate)}
            </div>
          </div>

          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            padding: '8px 12px',
            backgroundColor: daysDiff > 0 ? '#fff3cd' : '#d4edda',
            borderRadius: '4px',
          }}>
            <Icon
              icon={daysDiff > 0 ? 'arrow-right' : 'arrow-left'}
              color={daysDiff > 0 ? '#856404' : '#155724'}
            />
            <span style={{
              fontWeight: 600,
              color: daysDiff > 0 ? '#856404' : '#155724',
            }}>
              {Math.abs(daysDiff)} day{Math.abs(daysDiff) !== 1 ? 's' : ''} {daysDiff > 0 ? 'later' : 'earlier'}
            </span>
          </div>

          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '11px', color: 'var(--pt-text-muted)', marginBottom: '4px' }}>
              TO
            </div>
            <div style={{ fontWeight: 600 }}>
              {formatDate(targetDate)}
            </div>
          </div>
        </div>

        {/* Violations */}
        {violations.length > 0 && (
          <div style={{ marginBottom: '16px' }}>
            {violations.filter(v => v.severity === 'ERROR').map((violation, i) => (
              <Callout
                key={i}
                intent={Intent.DANGER}
                icon="error"
                style={{ marginBottom: '8px' }}
              >
                <strong>{violation.type.replace(/_/g, ' ')}</strong>
                <div style={{ marginTop: '4px' }}>{violation.message}</div>
              </Callout>
            ))}
            {violations.filter(v => v.severity === 'WARNING').map((violation, i) => (
              <Callout
                key={i}
                intent={Intent.WARNING}
                icon="warning-sign"
                style={{ marginBottom: '8px' }}
              >
                <strong>{violation.type.replace(/_/g, ' ')}</strong>
                <div style={{ marginTop: '4px' }}>{violation.message}</div>
              </Callout>
            ))}
          </div>
        )}

        {/* Impact Assessment */}
        {isLoading ? (
          <div style={{ textAlign: 'center', padding: '24px' }}>
            <Spinner size={24} />
            <div style={{ marginTop: '8px', color: 'var(--pt-text-muted)' }}>
              Calculating impact...
            </div>
          </div>
        ) : impact ? (
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(2, 1fr)',
            gap: '12px',
            marginTop: '16px',
          }}>
            {/* Man-hour Impact */}
            <div style={{
              padding: '12px',
              backgroundColor: 'var(--pt-app-secondary-background-color)',
              borderRadius: '6px',
            }}>
              <div style={{
                fontSize: '11px',
                fontWeight: 600,
                color: 'var(--pt-text-muted)',
                marginBottom: '8px',
              }}>
                MAN-HOUR IMPACT
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
                <span style={{ fontSize: '12px' }}>Source Week:</span>
                <Tag minimal>
                  {impact.manhourChange.sourceWeek.required}h / {impact.manhourChange.sourceWeek.available}h
                </Tag>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                <span style={{ fontSize: '12px' }}>Target Week:</span>
                <Tag
                  minimal
                  intent={impact.manhourChange.targetWeek.required > impact.manhourChange.targetWeek.available
                    ? Intent.DANGER
                    : Intent.NONE
                  }
                >
                  {impact.manhourChange.targetWeek.required}h / {impact.manhourChange.targetWeek.available}h
                </Tag>
              </div>
            </div>

            {/* Cost Impact */}
            <div style={{
              padding: '12px',
              backgroundColor: 'var(--pt-app-secondary-background-color)',
              borderRadius: '6px',
            }}>
              <div style={{
                fontSize: '11px',
                fontWeight: 600,
                color: 'var(--pt-text-muted)',
                marginBottom: '8px',
              }}>
                COST IMPACT
              </div>
              <div style={{
                fontSize: '18px',
                fontWeight: 600,
                color: impact.costChange > 0 ? '#d9534f' : impact.costChange < 0 ? '#5cb85c' : 'inherit',
              }}>
                {impact.costChange > 0 ? '+' : ''}{impact.costChange.toFixed(2)} HKD
              </div>
            </div>

            {/* Baseline Drift */}
            <div style={{
              padding: '12px',
              backgroundColor: 'var(--pt-app-secondary-background-color)',
              borderRadius: '6px',
            }}>
              <div style={{
                fontSize: '11px',
                fontWeight: 600,
                color: 'var(--pt-text-muted)',
                marginBottom: '8px',
              }}>
                BASELINE DRIFT
              </div>
              <div style={{
                fontSize: '18px',
                fontWeight: 600,
                color: Math.abs(impact.driftFromBaseline) > 7 ? '#d9534f' : 'inherit',
              }}>
                {impact.driftFromBaseline > 0 ? '+' : ''}{impact.driftFromBaseline} days
              </div>
            </div>

            {/* Conflicts */}
            {impact.conflictsCreated.length > 0 && (
              <div style={{
                padding: '12px',
                backgroundColor: '#fff3cd',
                borderRadius: '6px',
              }}>
                <div style={{
                  fontSize: '11px',
                  fontWeight: 600,
                  color: '#856404',
                  marginBottom: '8px',
                }}>
                  CONFLICTS CREATED
                </div>
                {impact.conflictsCreated.map((conflict, i) => (
                  <Tag key={i} intent={Intent.WARNING} minimal style={{ marginRight: '4px', marginBottom: '4px' }}>
                    {conflict}
                  </Tag>
                ))}
              </div>
            )}
          </div>
        ) : null}
      </DialogBody>

      <DialogFooter
        actions={
          <>
            <Button
              onClick={onCancel}
              disabled={isLoading}
            >
              Cancel
            </Button>
            <Button
              intent={hasErrors ? Intent.DANGER : hasWarnings ? Intent.WARNING : Intent.PRIMARY}
              onClick={onConfirm}
              disabled={isLoading || hasErrors}
              icon={hasWarnings ? 'warning-sign' : 'tick'}
            >
              {hasErrors ? 'Cannot Reschedule' : hasWarnings ? 'Reschedule Anyway' : 'Confirm Reschedule'}
            </Button>
          </>
        }
      />
    </Dialog>
  );
}

export default DragConfirmationDialog;

