  1219→          <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
  1220→            <p>Shows PM schedule from {detailFromDate} to {detailToDate}</p>
  1221→            <ul style={{ textAlign: 'left', maxWidth: '300px', margin: '8px auto' }}>
  1222→              <li>Full PM editing interface</li>
  1223→              <li>Constraint validation feedback</li>
  1224→              <li>Material availability status</li>
  1225→              <li>Change history timeline</li>
  1226→            </ul>
  1227→          </div>
  1228→        </NonIdealState>
  1229→      );
  1230→    }
  1231→
  1232→    return (
  1233→      <DetailCardOverlay
  1234→        data={detailData}
  1235→        fromDate={new Date(detailFromDate)}
  1236→        toDate={new Date(detailToDate)}
  1237→        width={DEFAULT_CANVAS_WIDTH}
  1238→        height={DEFAULT_CANVAS_HEIGHT}
  1239→        selectedPmIds={canvasState.selection.selectedPmIds}
  1240→        expandedPmIds={detailExpandedPmIds}
  1241→        onPmSelect={handleDetailPmSelect}
  1242→        onPmExpand={handleDetailPmExpand}
  1243→        onPmCollapse={handleDetailPmCollapse}
  1244→        onPmEdit={handleDetailPmEdit}
  1245→        onPmLock={handleDetailPmLock}
  1246→        onPmUnlock={handleDetailPmUnlock}
  1247→        onViewHistory={handleDetailViewHistory}
  1248→      />
  1249→    );
  1250→  };
  1251→
  1252→  // Handle focus events to detect keyboard vs mouse navigation
  1253→  const handleFocus = () => {
  1254→    // Focus visible only if triggered by keyboard
  1255→    if (isKeyboardNavigationRef.current) {
  1256→      uiActions.setFocusVisible(true);
  1257→    }
  1258→  };
  1259→
  1260→  const handleBlur = () => {
  1261→    // Reset keyboard navigation flag on blur
  1262→    isKeyboardNavigationRef.current = false;
  1263→    uiActions.setFocusVisible(false);
  1264→  };
  1265→
  1266→  const handleMouseDownForA11y = (event: React.MouseEvent) => {
  1267→    // Mouse click resets keyboard navigation mode
  1268→    isKeyboardNavigationRef.current = false;
  1269→    uiActions.setFocusVisible(false);
  1270→    // Call original handler
  1271→    handleMouseDown(event);
  1272→  };
  1273→
  1274→  const handleKeyDownForA11y = (event: React.KeyboardEvent) => {
  1275→    // Tab key indicates keyboard navigation
  1276→    if (event.key === 'Tab') {
  1277→      isKeyboardNavigationRef.current = true;
  1278→    }
  1279→    // Call original handler
  1280→    handleKeyDown(event);
  1281→  };
  1282→
  1283→  // Calculate visible focus ring style
  1284→  const focusRingStyle: React.CSSProperties = focusVisible ? {
  1285→    outline: FOCUS_RING_STYLES.default.outline,
  1286→    outlineOffset: FOCUS_RING_STYLES.default.outlineOffset,
  1287→    boxShadow: FOCUS_RING_STYLES.default.boxShadow,
  1288→  } : {
  1289→    outline: 'none',
  1290→  };
  1291→
  1292→  // Calculate transition style (respects reduced motion)
  1293→  const transitionStyle = isPanning || reducedMotion ? 'none' : 'transform 0.1s ease-out';
  1294→
  1295→  // Generate ARIA description
  1296→  const ariaDescription = `PM schedule canvas showing ${zoomLevel.replace('_', ' ')} view from ${viewport.startDate} to ${viewport.endDate}. ${viewport.trainIds.length || 'All'} trains visible. Use arrow keys to pan, plus/minus to zoom, 1-5 to switch views. Press question mark for full keyboard shortcuts help.`;
  1297→
  1298→  return (
  1299→    <div
  1300→      ref={containerRef}
  1301→      className="mms-canvas"
  1302→      data-testid="infinite-canvas"
  1303→      tabIndex={0}
  1304→      // ARIA attributes for accessibility (WCAG 2.1 AA)
  1305→      role="application"
  1306→      aria-label="PM Schedule Canvas"
  1307→      aria-description={ariaDescription}
  1308→      aria-roledescription="Interactive PM scheduling canvas"
  1309→      aria-busy={strategicLoading || tacticalLoading || operationalLoading || detailLoading}
  1310→      style={{
  1311→        flex: 1,
  1312→        position: 'relative',
  1313→        overflow: 'hidden',
  1314→        backgroundColor: 'var(--pt-app-background-color, #f5f8fa)',
  1315→        cursor: isPanning ? 'grabbing' : 'grab',
  1316→        ...focusRingStyle,
  1317→      }}
  1318→      onWheel={handleWheel}
  1319→      onMouseDown={handleMouseDownForA11y}
  1320→      onMouseUp={handleMouseUp}
  1321→      onMouseLeave={handleMouseUp}
  1322→      onMouseMove={handleMouseMove}
  1323→      onKeyDown={handleKeyDownForA11y}
  1324→      onFocus={handleFocus}
  1325→      onBlur={handleBlur}
  1326→    >
  1327→      {/* Hidden screen reader status region for canvas state */}
  1328→      <div
  1329→        role="status"
  1330→        aria-live="polite"
  1331→        aria-atomic="true"
  1332→        className="sr-only"
  1333→        style={{
  1334→          position: 'absolute',
  1335→          width: '1px',
