  1342→          border: 0,
  1343→        }}
  1344→      >
  1345→        {`Zoom: ${zoomLevel.replace('_', ' ')}. Viewing ${viewport.startDate} to ${viewport.endDate}.`}
  1346→      </div>
  1347→
  1348→      <div
  1349→        style={{
  1350→          position: 'absolute',
  1351→          top: 0,
  1352→          left: 0,
  1353→          right: 0,
  1354→          bottom: 0,
  1355→          transform: `translate(${-canvasState.panX}px, ${-canvasState.panY}px)`,
  1356→          transition: transitionStyle,
