  1366→        zIndex: 10,
  1367→      }}>
  1368→        <Card elevation={1} style={{ padding: '8px 12px' }}>
  1369→          <div style={{ fontSize: '11px', color: 'var(--pt-text-muted)', marginBottom: '4px' }}>
  1370→            Zoom Level
  1371→          </div>
  1372→          <div style={{ fontSize: '14px', fontWeight: 600 }}>
  1373→            {zoomLevel.replace('_', ' ')}
  1374→          </div>
  1375→          <div style={{ fontSize: '11px', fontFamily: 'monospace' }}>
  1376→            {zoom.toFixed(1)} / 20
  1377→          </div>
  1378→        </Card>
  1379→      </div>
  1380→
  1381→      {/* Bottom-left controls: Minimap and Viewport Info */}
  1382→      <div style={{
  1383→        position: 'absolute',
  1384→        bottom: '12px',
  1385→        left: '12px',
  1386→        zIndex: 10,
  1387→        display: 'flex',
  1388→        flexDirection: 'column',
  1389→        gap: '8px',
  1390→      }}>
  1391→        {/* Minimap navigation */}
  1392→        <Minimap />
  1393→
  1394→        {/* Viewport info */}
  1395→        <Card elevation={1} style={{ padding: '8px 12px' }}>
  1396→          <div style={{ fontSize: '11px' }}>
  1397→            <span style={{ color: 'var(--pt-text-muted)' }}>Viewport: </span>
  1398→            <span style={{ fontFamily: 'monospace' }}>
  1399→              {viewport.startDate} to {viewport.endDate}
  1400→            </span>
  1401→          </div>
  1402→          <div style={{ fontSize: '11px' }}>
  1403→            <span style={{ color: 'var(--pt-text-muted)' }}>Trains: </span>
  1404→            <span>{viewport.trainIds.length || 'All'}</span>
  1405→          </div>
  1406→        </Card>
  1407→      </div>
  1408→
  1409→      {(canvasState.layers.manhourOverlay || canvasState.layers.driftOverlay || canvasState.layers.baselineShadow) && (
  1410→        <div style={{
  1411→          position: 'absolute',
  1412→          top: '12px',
  1413→          left: '12px',
  1414→          zIndex: 10,
  1415→          display: 'flex',
  1416→          gap: '4px',
  1417→        }}>
  1418→          {canvasState.layers.manhourOverlay && (
  1419→            <Tag intent="primary" icon="chart">Man-hours</Tag>
  1420→          )}
  1421→          {canvasState.layers.driftOverlay && (
  1422→            <Tag intent="warning" icon="delta">Drift</Tag>
  1423→          )}
  1424→          {canvasState.layers.baselineShadow && (
  1425→            <Tag
  1426→              minimal
  1427→              icon={overlayState.baselineShadowLoading ? 'time' : 'git-commit'}
  1428→              intent={overlayState.baselineShadowError ? 'danger' : 'none'}
  1429→              title={overlayState.baselineShadowData
  1430→                ? `${overlayState.baselineShadowData.summary.movedPms} moved, ${overlayState.baselineShadowData.summary.addedPms} added, ${overlayState.baselineShadowData.summary.removedPms} removed`
  1431→                : overlayState.baselineShadowError || 'Loading...'}
  1432→            >
  1433→              {overlayState.baselineShadowLoading ? 'Loading...' : 'Baseline'}
  1434→            </Tag>
  1435→          )}
  1436→        </div>
  1437→      )}
  1438→
  1439→      {/* Baseline Legend - shows when baseline shadow is active */}
  1440→      {canvasState.layers.baselineShadow && overlayState.baselineShadowData && (
  1441→        <BaselineLegend
  1442→          summary={overlayState.baselineShadowData.summary}
  1443→          baselineName={overlayState.baselineShadowData.baselineName}
  1444→          onClose={() => canvasActions.toggleLayer('baselineShadow')}
  1445→        />
  1446→      )}
  1447→
  1448→      {/* Drag Confirmation Dialog */}
  1449→      <DragConfirmationDialog
  1450→        isOpen={dragConfirmRef.current.isOpen}
  1451→        pmCode={dragConfirmRef.current.pmCode}
  1452→        trainNumber={dragConfirmRef.current.trainNumber}
  1453→        sourceDate={dragConfirmRef.current.sourceDate}
  1454→        targetDate={dragConfirmRef.current.targetDate}
  1455→        impact={dragConfirmRef.current.impact}
  1456→        violations={pmState.drag.constraintViolations}
  1457→        isLoading={dragConfirmRef.current.isLoadingImpact}
  1458→        onConfirm={handleDragConfirm}
  1459→        onCancel={handleDragCancel}
  1460→      />
  1461→
  1462→      {/* Keyboard Shortcuts Dialog */}
  1463→      <KeyboardShortcutsDialog />
  1464→
  1465→      {/* Keyboard shortcut hint in corner */}
